MONTH_DAYS = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
# Cumulative days before each month (index 0 = before Jan, index 1 = before Feb, ...)
CUMULATIVE_DAYS = [sum(MONTH_DAYS[:i]) for i in range(12)]

def parse_date(s):
    """Parse 'YYYY-MM-DD' string to (year, month, day) tuple."""
    parts = s.split("-")
    if len(parts) != 3:
        raise ValueError(f"Invalid date format: {s}")
    year, month, day = int(parts[0]), int(parts[1]), int(parts[2])
    if month < 1 or month > 12:
        raise ValueError(f"Invalid month: {month}")
    if day < 1 or day > MONTH_DAYS[month - 1]:
        raise ValueError(f"Invalid day: {day} for month {month}")
    return (year, month, day)

def days_between(date1, date2):
    """Approximate days between two date strings (ignoring leap years)."""
    y1, m1, d1 = parse_date(date1)
    y2, m2, d2 = parse_date(date2)
    days1 = y1 * 365 + CUMULATIVE_DAYS[m1 - 1] + d1
    days2 = y2 * 365 + CUMULATIVE_DAYS[m2 - 1] + d2
    return abs(days2 - days1)

